arguments.command:
# The .so is stripped but may have dynamic symbols. Let's check with readelf (cross-arch capable)
cd /tmp/sv-7a8d214200404ff9be67c7720acc853e
readelf -S libmonosgen-2.0.so.sym | grep -E 'symtab|dynsym|debug' 2>&1
echo "---"
# Check dynamic symbol count
readelf --dyn-syms libmonosgen-2.0.so.sym 2>/dev/null | wc -l
echo "---"
# Try to find symbols near our PC offsets using dynamic symbol table
# Frame addresses: 0x222098, 0x2241ac, 0x1abc80, 0x1abd14, 0x16dfa4, 0x16db6c, 0x16de04
for addr in 0x222098 0x2241ac 0x1abc80 0x1abd14 0x16dfa4 0x16db6c 0x16de04; do
  echo -n "Frame $addr -> "
  # Find the nearest symbol below this address in the dynsym table
  readelf --dyn-syms libmonosgen-2.0.so.sym 2>/dev/null | awk -v target="$addr" '
    BEGIN { target_dec = strtonum(target); best_name=""; best_addr=0; best_offset=target_dec }
    /FUNC/ {
      addr = strtonum("0x"$2);
      size = strtonum($3);
      if (addr <= target_dec && (target_dec - addr) < best_offset) {
        best_offset = target_dec - addr;
        best_addr = addr;
        best_name = $NF;
        best_size = size;
      }
    }
    END {
      if (best_name != "") {
        printf "%s + 0x%x (func at 0x%x, size %d)\n", best_name, best_offset, best_addr, best_size
      } else {
        print "(no match)"
      }
    }'
done

